import { ref, computed } from 'vue'
import { showToast } from '@/components/ToastMessage'
import { user } from '@/api/user'

// 定义默认布局配置，与后端保持一致
const DEFAULT_LAYOUT = {
  basic_info: { order: 1, visible: true },
  job_intention: { order: 2, visible: true },
  work_experience: { order: 3, visible: true },
  education: { order: 4, visible: false },
  project: { order: 5, visible: false },
  skill: { order: 6, visible: false },
  certificate: { order: 7, visible: false },
  language: { order: 8, visible: false },
  portfolio: { order: 9, visible: false },
  social_link: { order: 10, visible: false }
}

export function useModules() {
  const loading = ref(false)
  const activeModules = ref([])
  const inactiveModules = ref([])
  const allModules = ref({})

  // 获取布局数据
  const fetchLayout = async () => {
    try {
      loading.value = true
      const response = await user.getProfileLayout()

      if (response.data?.code === 200) {
        // 获取布局数据，如果为空则使用默认布局
        const layoutData = response.data.data.layout || DEFAULT_LAYOUT

        // 确保所有默认模块都存在
        const normalizedLayout = Object.entries(DEFAULT_LAYOUT).reduce((acc, [key, defaultValue]) => {
          acc[key] = {
            order: layoutData[key]?.order || defaultValue.order,
            visible: layoutData[key]?.visible ?? defaultValue.visible
          }
          return acc
        }, {})

        console.log('规范化后的布局数据:', normalizedLayout)

        // 保存所有模块信息（排除基本信息模块）
        const { basic_info, ...otherModules } = normalizedLayout
        allModules.value = otherModules

        // 分离激活和未激活的模块
        const [active, inactive] = Object.entries(otherModules).reduce(
          ([active, inactive], [type, config]) => {
            const moduleData = {
              type,
              order: config.order,
              visible: config.visible,
              data: null
            }

            if (config.visible) {
              active.push(moduleData)
            } else {
              inactive.push(moduleData)
            }

            return [active, inactive]
          },
          [[], []]
        )

        // 更新状态
        activeModules.value = active.sort((a, b) => a.order - b.order)
        inactiveModules.value = inactive.sort((a, b) => a.order - b.order)
      }
    } catch (error) {
      console.error('获取布局失败:', error)
      showToast(error.message || '获取布局失败', 'error')
    } finally {
      loading.value = false
    }
  }

  // 更新布局数据
  const updateLayout = async (newLayout) => {
    try {
      // 确保数据格式正确，并包含所有必要的模块
      const normalizedLayout = Object.entries(DEFAULT_LAYOUT).reduce((acc, [key, defaultValue]) => {
        acc[key] = {
          order: newLayout[key]?.order || defaultValue.order,
          visible: newLayout[key]?.visible ?? defaultValue.visible
        }
        return acc
      }, {})

      console.log('发送的布局数据:', { layout: normalizedLayout })

      const response = await user.updateProfileLayout({
        layout: normalizedLayout
      })

      if (response.data?.code !== 200) {
        throw new Error(response.data?.message || '更新布局失败')
      }

      return response
    } catch (error) {
      console.error('更新布局失败:', error)
      throw error
    }
  }

  // 移除模块
  const removeModule = async (moduleType) => {
    if (moduleType === 'basic_info') return

    try {
      loading.value = true

      const newLayout = { ...allModules.value }
      if (newLayout[moduleType]) {
        newLayout[moduleType] = {
          ...newLayout[moduleType],
          visible: false,
          order: newLayout[moduleType]?.order || 0
        }
      }

      await updateLayout(newLayout)
      await fetchLayout()
      showToast('模块移除成功', 'success')
    } catch (error) {
      console.error('移除模块失败:', error)
      showToast(error.message || '移除模块失败，请重试', 'error')
      throw error
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    if (moduleType === 'basic_info') return

    try {
      loading.value = true

      const newLayout = { ...allModules.value }
      const newOrder = Math.max(...Object.values(newLayout).map(m => m.order || 0)) + 1

      newLayout[moduleType] = {
        ...newLayout[moduleType],
        visible: true,
        order: newOrder
      }

      await updateLayout(newLayout)
      await fetchLayout()
      showToast('模块添加成功', 'success')
    } catch (error) {
      console.error('添加模块失败:', error)
      showToast(error.message || '添加模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 更新模块顺序
  const updateOrder = async (newOrder) => {
    try {
      loading.value = true

      const newLayout = { ...allModules.value }

      // 更新排序
      newOrder.forEach((module, index) => {
        if (newLayout[module.type]) {
          newLayout[module.type] = {
            ...newLayout[module.type],
            order: index + 1
          }
        }
      })

      const response = await user.updateProfileLayout({ layout: newLayout })

      if (response.data?.code === 200) {
        // 更新本地状态
        allModules.value = newLayout
        // 重新排序激活的模块
        activeModules.value = activeModules.value
          .map(module => ({
            ...module,
            order: newLayout[module.type]?.order || module.order
          }))
          .sort((a, b) => a.order - b.order)
        showToast('布局更新成功', 'success')
      } else {
        throw new Error(response.data?.message || '更新布局失败')
      }
    } catch (error) {
      console.error('更新布局失败:', error)
      showToast(error.message || '更新布局失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    allModules,
    fetchLayout,
    removeModule,
    addModule,
    updateOrder
  }
}
